// Consolidate extracted text from any upload format (PDF, DOCX, TXT)
const items = $input.all();
let briefText = '';

for (const item of items) {
  if (item.json.text) {
    briefText += item.json.text;
  } else if (item.json.data) {
    briefText += item.json.data;
  } else if (typeof item.json === 'string') {
    briefText += item.json;
  }
}

// Fallback: if text extraction from binary failed, try raw body
if (!briefText && items[0]?.json?.body) {
  briefText = typeof items[0].json.body === 'string'
    ? items[0].json.body
    : JSON.stringify(items[0].json.body);
}

if (!briefText || briefText.trim().length < 20) {
  throw new Error(
    'ERROR: No valid assignment brief detected. Please upload your assignment brief as PDF, DOCX, or TXT.'
  );
}

return [{
  json: {
    briefText: briefText.trim(),
    uploadTimestamp: new Date().toISOString()
  }
}];

// Parse the Anthropic extraction response into structured JSON
const rawResponse = $input.first().json.message?.content
  || (typeof $input.first().json.response === 'object' ? JSON.stringify($input.first().json.response) : $input.first().json.response)
  || $input.first().json.text
  || $input.first().json.output
  || '';

let extracted;
try {
  // Try to extract JSON from the response (handle markdown code blocks)
  const jsonMatch = rawResponse.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    extracted = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('No JSON found in response');
  }
} catch (e) {
  throw new Error(`Failed to parse brief extraction: ${e.message}. Raw: ${rawResponse.substring(0, 500)}`);
}

// Validate required fields
if (!extracted.tasks || extracted.tasks.length === 0) {
  throw new Error('No tasks were extracted from the assignment brief. Please check the uploaded document.');
}

// Calculate word allocations if not provided
const totalWordCount = extracted.wordCount || 3000;
const totalWeight = extracted.tasks.reduce((sum, t) => sum + (t.markWeight || 0), 0);

if (totalWeight > 0) {
  extracted.tasks = extracted.tasks.map(t => ({
    ...t,
    suggestedWordAllocation: t.suggestedWordAllocation
      || Math.round((t.markWeight / totalWeight) * totalWordCount)
  }));
} else {
  const perTask = Math.round(totalWordCount / extracted.tasks.length);
  extracted.tasks = extracted.tasks.map(t => ({
    ...t,
    suggestedWordAllocation: t.suggestedWordAllocation || perTask
  }));
}

return [{
  json: {
    briefText: $('Consolidate Brief Text').first().json.briefText,
    extraction: extracted
  }
}];

// Parse the structure generation response
const rawResponse = $input.first().json.message?.content
  || $input.first().json.response
  || $input.first().json.text
  || '';

let structure;
try {
  const jsonMatch = rawResponse.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    structure = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('No JSON found in structure response');
  }
} catch (e) {
  throw new Error(`Failed to parse structure: ${e.message}`);
}

// Validate no generic sections were included unless explicitly required
const genericHeadings = ['introduction', 'conclusion', 'literature review', 'analysis', 'discussion'];
const extraction = $('Parse & Validate Extraction').first().json.extraction;
const briefText = $('Consolidate Brief Text').first().json.briefText.toLowerCase();

const filteredSections = structure.sections.filter(section => {
  const headingLower = section.heading.toLowerCase();
  const isGeneric = genericHeadings.some(g => headingLower === g || headingLower === `${g} section`);

  if (isGeneric) {
    // Check if the brief explicitly requires this section
    const briefRequiresIt = extraction.explicitRequirements?.some(
      r => r.toLowerCase().includes(headingLower)
    ) || briefText.includes(headingLower);

    return briefRequiresIt;
  }
  return true;
});

structure.sections = filteredSections;

return [{
  json: {
    briefText: $('Consolidate Brief Text').first().json.briefText,
    extraction: extraction,
    structure: structure
  }
}];

// Parse the written content
const rawResponse = $input.first().json.message?.content
  || (typeof $input.first().json.response === 'object' ? JSON.stringify($input.first().json.response) : $input.first().json.response)
  || $input.first().json.text
  || $input.first().json.output
  || '';

let writtenContent;
try {
  const jsonMatch = rawResponse.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    writtenContent = JSON.parse(jsonMatch[0]);
  } else {
    // If not JSON, treat the entire response as content
    writtenContent = {
      sections: [{ heading: 'Assignment Content', content: rawResponse }],
      references: []
    };
  }
} catch (e) {
  // Fallback: use raw text
  writtenContent = {
    sections: [{ heading: 'Assignment Content', content: rawResponse }],
    references: []
  };
}

return [{
  json: {
    briefText: $('Consolidate Brief Text').first().json.briefText,
    extraction: $('Parse & Validate Extraction').first().json.extraction,
    structure: $('Validate Structure (No Generic Sections)').first().json.structure,
    writtenContent: writtenContent
  }
}];

// Parse the enhanced content from Anthropic
const rawResponse = $input.first().json.message?.content
  || (typeof $input.first().json.response === 'object' ? JSON.stringify($input.first().json.response) : $input.first().json.response)
  || $input.first().json.text
  || $input.first().json.output
  || '';

let enhancedContent;
try {
  const jsonMatch = rawResponse.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    enhancedContent = JSON.parse(jsonMatch[0]);
  } else {
    enhancedContent = $('Parse Written Content').first().json.writtenContent;
  }
} catch (e) {
  enhancedContent = $('Parse Written Content').first().json.writtenContent;
}

return [{
  json: {
    briefText: $('Consolidate Brief Text').first().json.briefText,
    extraction: $('Parse & Validate Extraction').first().json.extraction,
    structure: $('Validate Structure (No Generic Sections)').first().json.structure,
    enhancedContent: enhancedContent
  }
}];

// Parse validation results and determine if refinement is needed
const rawResponse = $input.first().json.message?.content
  || (typeof $input.first().json.response === 'object' ? JSON.stringify($input.first().json.response) : $input.first().json.response)
  || $input.first().json.text
  || $input.first().json.output
  || '';

let validation;
try {
  const jsonMatch = rawResponse.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    validation = JSON.parse(jsonMatch[0]);
  } else {
    validation = { overallScore: 75, passesValidation: true, requiresRefinement: false };
  }
} catch (e) {
  validation = { overallScore: 75, passesValidation: true, requiresRefinement: false };
}

return [{
  json: {
    briefText: $('Consolidate Brief Text').first().json.briefText,
    extraction: $('Parse & Validate Extraction').first().json.extraction,
    structure: $('Validate Structure (No Generic Sections)').first().json.structure,
    enhancedContent: $('Parse Enhanced Content').first().json.enhancedContent,
    validation: validation,
    requiresRefinement: validation.requiresRefinement === true && validation.overallScore < 80,
    iterationCount: ($input.first().json.iterationCount || 0) + 1
  }
}];

// Parse refined content and loop back for re-validation
const rawResponse = $input.first().json.message?.content
  || (typeof $input.first().json.response === 'object' ? JSON.stringify($input.first().json.response) : $input.first().json.response)
  || $input.first().json.text
  || $input.first().json.output
  || '';

let refinedContent;
try {
  const jsonMatch = rawResponse.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    refinedContent = JSON.parse(jsonMatch[0]);
  } else {
    refinedContent = $('Parse Enhanced Content').first().json.enhancedContent;
  }
} catch (e) {
  refinedContent = $('Parse Enhanced Content').first().json.enhancedContent;
}

return [{
  json: {
    briefText: $input.first().json.briefText,
    extraction: $input.first().json.extraction,
    structure: $input.first().json.structure,
    enhancedContent: refinedContent,
    iterationCount: $input.first().json.iterationCount
  }
}];

// Generate the final HTML document for download
const data = $input.first().json;
const content = data.enhancedContent;
const extraction = data.extraction;
const structure = data.structure;
const validation = data.validation;

const title = structure?.title || extraction?.subjectArea || 'Academic Assignment';
const refStyle = extraction?.referencingStyle || 'Harvard';
const academicLevel = extraction?.academicLevel || 'MSc';
const wordCount = structure?.totalWordCount || extraction?.wordCount || 'N/A';

// Build sections HTML
let sectionsHtml = '';
const sections = content?.sections || [];
for (let i = 0; i < sections.length; i++) {
  const section = sections[i];
  const heading = section.heading || `Section ${i + 1}`;
  // Convert newlines to paragraphs
  const paragraphs = (section.content || '')
    .split(/\n\n+/)
    .filter(p => p.trim())
    .map(p => `<p>${p.trim()}</p>`)
    .join('\n');

  sectionsHtml += `
    <div class="section">
      <h2>${i + 1}. ${heading}</h2>
      ${paragraphs}
    </div>`;
}

// Build references HTML
let referencesHtml = '';
const references = content?.references || [];
if (references.length > 0) {
  referencesHtml = `
    <div class="section references">
      <h2>References</h2>
      <div class="reference-list">
        ${references.map(r => `<p class="reference-entry">${r}</p>`).join('\n')}
      </div>
    </div>`;
}

// Build validation summary
let validationHtml = '';
if (validation) {
  validationHtml = `
    <div class="validation-summary">
      <p><strong>Quality Score:</strong> ${validation.overallScore || 'N/A'}/100</p>
      <p><strong>Iterations:</strong> ${data.iterationCount || 1}</p>
    </div>`;
}

const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${title}</title>
  <style>
    @page {
      size: A4;
      margin: 2.54cm;
    }
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }
    body {
      font-family: 'Times New Roman', 'Georgia', serif;
      font-size: 12pt;
      line-height: 2;
      color: #1a1a1a;
      background: #ffffff;
      max-width: 210mm;
      margin: 0 auto;
      padding: 2.54cm;
    }
    .cover-page {
      display: flex;
      flex-direction: column;
      justify-content: center;
      align-items: center;
      min-height: 80vh;
      text-align: center;
      page-break-after: always;
      border-bottom: 3px double #2c3e50;
      padding-bottom: 40px;
    }
    .cover-page h1 {
      font-size: 24pt;
      font-weight: bold;
      color: #2c3e50;
      margin-bottom: 30px;
      line-height: 1.3;
      max-width: 80%;
    }
    .cover-meta {
      font-size: 14pt;
      color: #555;
      margin-top: 20px;
    }
    .cover-meta p {
      margin: 8px 0;
    }
    .toc {
      page-break-after: always;
      padding: 40px 0;
    }
    .toc h2 {
      font-size: 18pt;
      color: #2c3e50;
      border-bottom: 2px solid #2c3e50;
      padding-bottom: 10px;
      margin-bottom: 25px;
    }
    .toc ul {
      list-style: none;
      padding: 0;
    }
    .toc li {
      padding: 8px 0;
      border-bottom: 1px dotted #ccc;
      font-size: 12pt;
    }
    .toc li a {
      text-decoration: none;
      color: #2c3e50;
    }
    .section {
      margin-bottom: 30px;
      page-break-inside: avoid;
    }
    .section h2 {
      font-size: 16pt;
      color: #2c3e50;
      margin-bottom: 15px;
      margin-top: 30px;
      border-bottom: 1px solid #ddd;
      padding-bottom: 8px;
    }
    .section p {
      text-align: justify;
      margin-bottom: 12px;
      text-indent: 0;
    }
    .references {
      page-break-before: always;
    }
    .reference-list {
      padding-left: 0;
    }
    .reference-entry {
      margin-bottom: 10px;
      padding-left: 40px;
      text-indent: -40px;
      line-height: 1.8;
      font-size: 11pt;
    }
    .validation-summary {
      margin-top: 40px;
      padding: 15px;
      background: #f8f9fa;
      border: 1px solid #dee2e6;
      border-radius: 4px;
      font-size: 10pt;
      color: #666;
    }
    @media print {
      body {
        padding: 0;
      }
      .validation-summary {
        display: none;
      }
    }
  </style>
</head>
<body>

  <!-- Cover Page -->
  <div class="cover-page">
    <h1>${title}</h1>
    <div class="cover-meta">
      <p><strong>Academic Level:</strong> ${academicLevel}</p>
      <p><strong>Referencing Style:</strong> ${refStyle}</p>
      <p><strong>Word Count:</strong> ${wordCount}</p>
      <p><strong>Date:</strong> ${new Date().toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' })}</p>
    </div>
  </div>

  <!-- Table of Contents -->
  <div class="toc">
    <h2>Table of Contents</h2>
    <ul>
      ${sections.map((s, i) => `<li>${i + 1}. ${s.heading || 'Section ' + (i + 1)}</li>`).join('\n      ')}
      ${references.length > 0 ? '<li>References</li>' : ''}
    </ul>
  </div>

  <!-- Main Content -->
  ${sectionsHtml}

  <!-- References -->
  ${referencesHtml}

  <!-- Validation Summary (hidden on print) -->
  ${validationHtml}

</body>
</html>`;

// Convert to binary buffer for download
const buffer = Buffer.from(html, 'utf-8');
const fileName = title.replace(/[^a-zA-Z0-9\s]/g, '').replace(/\s+/g, '_').substring(0, 60) + '.html';

return [{
  json: {
    title: title,
    fileName: fileName,
    validationScore: validation?.overallScore || 'N/A',
    iterationCount: data.iterationCount || 1,
    sectionsCount: sections.length,
    referencesCount: references.length
  },
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'text/html',
      fileName: fileName,
      fileExtension: 'html'
    }
  }
}];

prompt.text:
=Write the COMPLETE assignment content based on the structure below. Write EVERY section in full.

ASSIGNMENT STRUCTURE:
{{ JSON.stringify($json.structure, null, 2) }}

EXTRACTED REQUIREMENTS:
{{ JSON.stringify($json.extraction, null, 2) }}

ORIGINAL BRIEF:
{{ $json.briefText }}

INSTRUCTIONS:
1. Write each section completely according to its word allocation
2. Follow the paragraph structure: Claim → Evidence → Critical Analysis → Link to task
3. Use the referencing style: {{ $json.extraction.referencingStyle || 'Harvard Cite Them Right' }}
4. Include in-text citations throughout
5. Maintain context continuity between sections
6. Avoid repetition across sections
7. End with a comprehensive reference list

Return the output as JSON with this format:
{
  "sections": [
    {
      "heading": "<section heading>",
      "content": "<full section content with in-text citations>"
    }
  ],
  "references": [
    "<full reference entry>"
  ]
}

=You are performing auto-refinement on an academic assignment. This is iteration {{ $json.iterationCount }} of maximum 3.

VALIDATION FEEDBACK:
{{ JSON.stringify($json.validation, null, 2) }}

CURRENT CONTENT:
{{ JSON.stringify($json.enhancedContent, null, 2) }}

ORIGINAL BRIEF:
{{ $json.briefText }}

CRITICAL ISSUES TO FIX:
{{ JSON.stringify($json.validation.criticalIssues || [], null, 2) }}

REFINEMENT SUGGESTIONS:
{{ JSON.stringify($json.validation.refinementSuggestions || [], null, 2) }}

INSTRUCTIONS:
1. Address ALL critical issues identified
2. Implement refinement suggestions where they improve quality
3. Improve clarity, depth, and coherence
4. Maintain the existing structure (do NOT add generic sections)
5. Keep word count within the required range

Return the refined content as JSON:
{
  "sections": [
    {
      "heading": "<section heading>",
      "content": "<refined section content>"
    }
  ],
  "references": [
    "<full reference entry>"
  ],
  "refinementChanges": ["<what was changed and why>"]
}
